function nCr(n, r) {
    if (r < 0 || r > n) return 0;
    r = Math.min(r, n - r);
    let result = 1;
    for (let i = 1; i <= r; i++) {
        result = (result * (n - r + i)) / i;
    }
    return Math.round(result);
}

var nthSmallest = function(n, k) {
    let m = n - 1;
    let result = 0;
    let remainingK = k;
    while (remainingK > 0) {
        let c = remainingK - 1;
        while (nCr(c + 1, remainingK) <= m) c++;
        result += Math.pow(2, c);
        m -= nCr(c, remainingK);
        remainingK--;
    }
    return result;
};
